  cursor: pointer;
  color: white;
  font-size: 12px;
  font-weight: 600;
  border-radius: 6px;
  transition: all 0.2s ease;
}
.save-btn-small {
  background: #6366f1;
}
.cancel-btn-small {
  background: #475569;
}
.save-btn-small:hover,
.cancel-btn-small:hover {
  transform: translateY(-1px);
}
@media(max-width: 1024px) {
  .leave-grid-layout {
    grid-template-columns: 1fr;
  }
}

