  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}
.profile-form-actions .save-btn:hover,
.profile-form-actions .cancel-btn:hover {
  transform: translateY(-2px);
}
/* ==========================
   LOGOUT BUTTON IN NAVBAR
========================== */
.logout-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 18px;
  border: none;
  border-radius: 10px;
  background: rgba(239, 68, 68, 0.1);
  border: 1px solid rgba(239, 68, 68, 0.2);
  color: #f87171;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}
.logout-btn:hover {
  background: #ef4444;
  color: white;
  transform: scale(1.03);
  box-shadow: 0 4px 12px rgba(239, 68, 68, 0.3);
}
.logout-btn svg {
  font-size: 16px;
}
/* ==========================
   TAB NAVIGATION SYSTEM
========================== */
.tab-navigation {
  display: flex;
  gap: 15px;
  margin-bottom: 25px;
  background: rgba(30, 41, 59, 0.4);
  padding: 8px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.05);
  width: fit-content;
}
.nav-tab-btn {
  padding: 10px 24px;
  border: none;
  background: transparent;
  color: #94a3b8;
  font-size: 15px;
  font-weight: 600;
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.3s ease;
}
.nav-tab-btn:hover {
  color: #fff;
  background: rgba(255, 255, 255, 0.05);
}
.nav-tab-btn.active {
  background: #6366f1;
  color: #fff;
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.25);
}
/* ==========================
   LEAVE REQUEST SYSTEM
========================== */
.leave-requests-container {
  animation: fadeUp 0.6s ease;
}
.leave-grid-layout {
  display: grid;
  grid-template-columns: 350px 1fr;
  gap: 30px;
  align-items: start;
}
.leave-card-form, 
.leave-history,
.leave-admin-panel {
  background: #1e293b;
  border-radius: 20px;
  padding: 30px;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.3);
  border: 1px solid rgba(255, 255, 255, 0.05);
}
.leave-card-form h2,
.leave-history h2,
.leave-admin-panel h2 {
  font-size: 22px;
  margin-bottom: 20px;
  color: #fff;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
  padding-bottom: 12px;
  text-align: left;
}
.leave-form-fields {
  display: flex;
  flex-direction: column;
  gap: 15px;
  text-align: left;
}
.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 15px;
}
.leave-form-fields textarea {
  padding: 12px;
  border: none;
  outline: none;
  border-radius: 10px;
  background: #0f172a;
  color: white;
  font-size: 14px;
  font-family: inherit;
  resize: vertical;
}
.apply-btn {
  margin-top: 10px;
  background: linear-gradient(45deg, #6366f1, #8b5cf6);
  width: 100%;
}
/* Leaves Table */
.leave-table-wrapper {
  overflow-x: auto;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.05);
}
.leave-table {
  width: 100%;
  border-collapse: collapse;
  text-align: left;
}
.leave-table th,
.leave-table td {
  padding: 16px 20px;
  font-size: 14px;
}
.leave-table th {
  background: #0f172a;
  color: #94a3b8;
  font-weight: 600;
  text-transform: uppercase;
  font-size: 12px;
  letter-spacing: 0.5px;
}
.leave-table tbody tr {
  border-bottom: 1px solid rgba(255, 255, 255, 0.03);
}
.leave-table tbody tr:last-child {
  border-bottom: none;
}
/* Status Badges */
.status-badge {
  display: inline-block;
  padding: 6px 12px;
  font-size: 12px;
  font-weight: 600;
  border-radius: 20px;
  text-transform: capitalize;
}
.status-badge.pending {
  background: rgba(245, 158, 11, 0.15);
  color: #f59e0b;
  border: 1px solid rgba(245, 158, 11, 0.25);
}
.status-badge.approved {
  background: rgba(16, 185, 129, 0.15);
  color: #10b981;
  border: 1px solid rgba(16, 185, 129, 0.25);
}
.status-badge.rejected {
  background: rgba(239, 68, 68, 0.15);
  color: #ef4444;
  border: 1px solid rgba(239, 68, 68, 0.25);
}
.mgr-comment {
  font-size: 12px;
  color: #94a3b8;
  margin-top: 4px;
  font-style: italic;
}
.text-muted {
  color: #64748b;
  font-style: italic;
  font-size: 13px;
}
/* Admin Leaves Management controls */
.actions-cell {
  display: flex;
  gap: 10px;
}
.approve-action-btn,
.reject-action-btn {
  padding: 8px 16px;
  border: none;
  cursor: pointer;
  color: white;
  font-size: 13px;
  font-weight: 600;
  border-radius: 8px;
  transition: all 0.3s ease;
}
.approve-action-btn {
  background: linear-gradient(45deg, #10b981, #059669);
}
.reject-action-btn {
  background: linear-gradient(45deg, #ef4444, #dc2626);
}
.approve-action-btn:hover,
.reject-action-btn:hover {
  transform: translateY(-2px);
}
/* Review inline inputs */
.review-inline-form {
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 250px;
}
.review-inline-form input {
  padding: 10px;
  border: none;
  outline: none;
  border-radius: 8px;
  background: #0f172a;
  color: white;
  font-size: 13px;
}
.review-actions {
  display: flex;
  gap: 8px;
}
.save-btn-small,
.cancel-btn-small {
  padding: 6px 12px;
  border: none;
  cursor: pointer;
  color: white;
  font-size: 12px;
  font-weight: 600;
  border-radius: 6px;
  transition: all 0.2s ease;
}
.save-btn-small {
  background: #6366f1;
}
.cancel-btn-small {
  background: #475569;
}
.save-btn-small:hover,
.cancel-btn-small:hover {
  transform: translateY(-1px);
}
@media(max-width: 1024px) {
  .leave-grid-layout {
    grid-template-columns: 1fr;
  }
}

