@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap");
/* Google Font */
*{
  margin:0;
  padding:0;
  box-sizing:border-box;
  font-family:"Poppins",sans-serif;
}
body{
  background:#0f172a;
  color:#fff;
}
.app{
  width:90%;
  max-width:1400px;
  margin:auto;
  padding:30px 0;
}
/* =========================
   NAVBAR
========================= */
.navbar{
  display:flex;
  justify-content:space-between;
  align-items:center;
  padding:20px 30px;
  margin-bottom:30px;
  border-radius:18px;

  background:rgba(255,255,255,.08);
  backdrop-filter:blur(12px);

  box-shadow:
  0 10px 35px rgba(0,0,0,.35);
}
.logo{
  font-size:28px;
  font-weight:700;
  color:#6366f1;
}
.logo span{
  color:white;
}
.nav-right{
  display:flex;
  align-items:center;
  gap:20px;
}
.icon{
  width:45px;
  height:45px;
  display:flex;
  align-items:center;
  justify-content:center;
  border-radius:50%;
  background:#1e293b;
  cursor:pointer;
  transition:.3s;
}
.icon:hover{
  background:#6366f1;
}
.profile{
  display:flex;
  align-items:center;
  gap:10px;
}
.profile img{
  width:45px;
  height:45px;
  border-radius:50%;
}
.profile h4{
  font-size:15px;
}
.profile p{
  font-size:12px;
  color:#b8b8b8;
}
/* =========================
 DASHBOARD
========================= */
.dashboard{
  display:grid;
  grid-template-columns:repeat(4,1fr);
  gap:25px; 
  margin-bottom:40px;
}
.card{
  background:#1e293b;
  border-radius:20px;
  padding:25px;

  transition:.35s;

  box-shadow:
  0 10px 25px rgba(0,0,0,.35);
}
.card:hover{
  transform:translateY(-8px);
}
.card h3{
  font-size:16px;
  color:#d7d7d7;
}
.card h1{
  margin-top:15px;
  font-size:34px;
}
.card.blue{
  border-left:6px solid #6366f1;
}
.card.green{
  border-left:6px solid #22c55e;
}
.card.orange{
  border-left:6px solid orange;
}
.card.red{
  border-left:6px solid crimson;
}
/* =========================
 SEARCH BAR
========================= */
.search-area{
  display:flex;
  justify-content:space-between;
  align-items:center;
  margin-bottom:30px;
  gap:20px;
}
.search-box{
  flex:1;
}
.search-box input{
  width:100%;
  padding:15px 20px;
  border:none;
  border-radius:14px;
  outline:none;
  font-size:15px;

  background:#1e293b;
  color:white;
}
.search-box input::placeholder{
  color:#9ca3af;
}
.add-btn{
  padding:15px 25px;
  border:none;
  border-radius:14px;
  cursor:pointer;
  color:white;
  font-size:15px;
  font-weight:600;

  background:linear-gradient(
  45deg,
  #6366f1,
  #8b5cf6);

  transition:.3s;
}
.add-btn:hover{
  transform:scale(1.05);
}
/* =========================
 EMPLOYEE GRID
========================= */
.employee-grid{

  display:grid;

  grid-template-columns:

  repeat(auto-fit,minmax(280px,1fr));

  gap:25px;

}
/* =========================
 EMPLOYEE CARD
========================= */
.employee-card{

  background:#1e293b;

  border-radius:18px;

  padding:25px;

  transition:.35s;

  box-shadow:

  0 10px 25px rgba(0,0,0,.3);

}
.employee-card:hover{

  transform:translateY(-10px);

}
.avatar{

  width:80px;

  height:80px;

  border-radius:50%;

  margin:auto;

  display:flex;

  align-items:center;

  justify-content:center;

  font-size:34px;

  font-weight:bold;

  background:

  linear-gradient(

  45deg,

  #6366f1,

  #8b5cf6);

}
.employee-card h2{

  text-align:center;

  margin-top:18px;

}
.employee-card h4{

  text-align:center;

  margin-top:5px;

  color:#c5c5c5;

  font-weight:400;

}
.info{

  margin-top:20px;

}
.info p{

  margin:10px 0;

  color:#d9d9d9;

}
/* ==========================
   EMPLOYEE FORM
========================== */
.employee-form {
  margin: 30px 0;
  padding: 30px;
  background: rgba(30, 41, 59, 0.95);
  border-radius: 20px;
  box-shadow: 0 10px 30px rgba(0,0,0,0.3);
}
.employee-form h2 {
  margin-bottom: 20px;
  color: #fff;
}
.form-grid {
  display: grid;
  grid-template-columns: repeat(2,1fr);
  gap: 20px;
}
.form-group {
  display: flex;
  flex-direction: column;
}
.form-group label {
  margin-bottom: 8px;
  font-size: 14px;
  color: #d1d5db;
}
.form-group input,
.form-group select {
  padding: 14px;
  border: none;
  outline: none;
  border-radius: 12px;
  background: #0f172a;
  color: white;
  font-size: 15px;
}
.form-group input::placeholder {
  color: #9ca3af;
}
.submit-btn {
  margin-top: 25px;
  padding: 15px 30px;
  border: none;
  border-radius: 12px;
  cursor: pointer;
  background: linear-gradient(45deg,#22c55e,#16a34a);
  color: white;
  font-size: 16px;
  font-weight: 600;
  transition: .3s;
}
.submit-btn:hover {
  transform: scale(1.05);
}
/* ==========================
   EMPLOYEE CARD DETAILS
========================== */
.employee-card .info {
  margin-top: 20px;
}
.employee-card .info p {
  margin: 10px 0;
  font-size: 14px;
}
.employee-card .info strong {
  color: #60a5fa;
}
/* ==========================
   ACTION BUTTONS
========================== */
.actions {
  display: flex;
  justify-content: space-between;
  margin-top: 25px;
}
.edit-btn,
.delete-btn {
  flex: 1;
  padding: 12px;
  border: none;
  cursor: pointer;
  color: white;
  font-size: 14px;
  border-radius: 10px;
  transition: .3s;
}
.edit-btn {
  margin-right: 10px;
  background: linear-gradient(45deg,#3b82f6,#2563eb);
}
.delete-btn {
  background: linear-gradient(45deg,#ef4444,#dc2626);
}
.edit-btn:hover,
.delete-btn:hover {
  transform: translateY(-3px);
}
/* ==========================
   EMPTY MESSAGE
========================== */
.empty {
  text-align: center;
  color: #94a3b8;
  font-size: 18px;
  padding: 40px;
}
/* ==========================
   SCROLLBAR
========================== */
::-webkit-scrollbar {
  width: 10px;
}
::-webkit-scrollbar-track {
  background: #0f172a;
}
::-webkit-scrollbar-thumb {
  background: #6366f1;
  border-radius: 20px;
}
::-webkit-scrollbar-thumb:hover {
  background: #4f46e5;
}
/* ==========================
   ANIMATIONS
========================== */
@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(25px);
  }

  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.employee-card,
.card,
.employee-form {
  animation: fadeUp .6s ease;
}
/* ==========================
   RESPONSIVE
========================== */
@media(max-width:1100px){

.dashboard{
grid-template-columns:repeat(2,1fr);
}

}
@media(max-width:768px){

.app{
width:95%;
}

.navbar{
flex-direction:column;
gap:20px;
}

.search-area{
flex-direction:column;
}

.form-grid{
grid-template-columns:1fr;
}

.dashboard{
grid-template-columns:1fr;
}

.employee-grid{
grid-template-columns:1fr;
}

.actions{
flex-direction:column;
gap:10px;
}

.edit-btn{
margin-right:0;
}

}
@media(max-width:500px){

.logo{
font-size:22px;
}

.card h1{
font-size:28px;
}

.employee-card{
padding:20px;
}

.avatar{
width:70px;
height:70px;
font-size:28px;
}

.submit-btn,
.add-btn{
width:100%;
}

}
.loading {
  text-align: center;
  font-size: 20px;
